// 10 STRESS TEST CASES - complex/ambiguous scenarios
const testCases = [
  {
    // Case 1: MIXED SIGNALS - sounds like no_response AND locator_complaint combined
    alert_id: "STRESS001",
    ticket_number: "2026022400001",
    station_codes: ["COMNCA"],
    issue_type: "Other",
    states: ["California"],
    customer_name: "Mike Torres",
    notes: "Excavator says Comcast locator came out but only marked half the lines then left and never came back. Its been 4 days now and excavator has called 3 times. Locator told him to stop calling and that he marked everything already but excavator can see the cable running through his trench unmarked. Wants a different locator sent out."
  },
  {
