    // Case 7: NOT AN 811 ISSUE AT ALL - wrong department entirely
    alert_id: "STRESS007",
    ticket_number: "2026022400007",
    station_codes: ["N/A"],
    issue_type: "Other",
    states: ["California"],
    customer_name: "Tom Baker",
    notes: "Caller wants to know if he needs a permit to build a fence in his backyard. He also wants to know if 811 can tell him where his property line is. He says his neighbor is encroaching on his land and he wants someone to come out and survey it."
  },
  {
    // Case 8: SYSTEM STATUS that overlaps with TICKET DELIVERY
    alert_id: "STRESS008",
    ticket_number: "2026022400008",
    station_codes: ["CALCBL"],
    issue_type: "Other",
    states: ["California"],
    customer_name: "Maria Gonzalez",
    notes: "Member called in and says they havent received any tickets in their DPP portal for the last 3 days but excavators are calling them saying they submitted tickets. She checked her email and the notification emails stopped coming too. She thinks her account might be suspended but she can still log in. She ran a search in DPP and the tickets show up there but no notifications are being triggered."
  },
  {
    // Case 9: MULTI-LANGUAGE / GARBLED NOTES with a real issue underneath
    alert_id: "STRESS009",
    ticket_number: "2026022400009",
    station_codes: ["COMNCA"],
    issue_type: "Other",
    states: ["California"],
    customer_name: "Wei Zhang",
    notes: "caller not speak english very well, he say he dig and hit something, maybe cable maybe pipe he not sure. he say comcast box is close and wire is orange. he stop work and want to know who to call. he say he had ticket but nobody come to mark. i give him damage reporting number but he want comcast to come look at what he hit."
  },
  {
    // Case 10: EVERYTHING AT ONCE - no_response + contact_info + system_status + angry
    alert_id: "STRESS010",
    ticket_number: "2026022400010",
    station_codes: ["PGESFR"],
    issue_type: "Other",
    states: ["California"],
    customer_name: "Dave Mitchell",
    notes: "CONTRACTOR HAS BEEN TRYING TO REACH PGE FOR 5 BUSINESS DAYS ON TICKET 2026021500333. THE PHONE NUMBER IN THE SYSTEM RINGS TO A RECORDING THAT SAYS THE NUMBER HAS BEEN CHANGED. HE TRIED SUBMITTING A POSITIVE RESPONSE ON BEHALF OF PGE THROUGH DPP BUT THE SYSTEM SAYS PGE IS NOT ELIGIBLE FOR THIRD PARTY RESPONSES. HE FOUND A DIFFERENT PGE NUMBER ONLINE AND CALLED IT BUT THEY SAID THEY DONT HANDLE 811 LOCATES. CONTRACTOR SAYS HE HAS 15 CREW MEMBERS SITTING IDLE AND IS THREATENING LEGAL ACTION IF SOMEONE DOESNT RESOLVE THIS TODAY."
  }
];

return testCases.map(tc => ({ json: tc }));

// Gather HubSpot Context - processes ALL items
const HS_TOKEN = 'Bearer pat-na1-YOUR_HUBSPOT_PAT_HERE';
const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const stationCodes = data.station_codes || [];
  const stationDetails = [];

  for (const code of stationCodes) {
    if (!code || code === 'N/A') {
      stationDetails.push({ station_code: code, found: false, details: null });
      continue;
    }

    try {
      const searchResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.hubapi.com/crm/v3/objects/2-35681060/search',
        headers: { 'Authorization': HS_TOKEN, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          filterGroups: [{
            filters: [{
              propertyName: 'station_code',
              operator: 'EQ',
              value: code
            }]
          }],
          properties: ['station_code', 'station_email', 'station_contact_name'],
          limit: 1
        })
      });

      const station = searchResponse.results?.[0];
      let rep_email = station?.properties?.station_email || null;
      let rep_name = station?.properties?.station_contact_name || null;
      let lookup_method = rep_email ? 'direct' : 'none';

      if (!rep_email && station) {
        try {
          const assocData = await this.helpers.httpRequest({
            method: 'GET',
            url: `https://api.hubapi.com/crm/v4/objects/2-35681060/${station.id}/associations/contacts`,
            headers: { 'Authorization': HS_TOKEN }
          });
          const contactId = assocData.results?.[0]?.toObjectId;
          if (contactId) {
            const contact = await this.helpers.httpRequest({
              method: 'GET',
              url: `https://api.hubapi.com/crm/v3/objects/contacts/${contactId}?properties=email,firstname,lastname`,
              headers: { 'Authorization': HS_TOKEN }
            });
            rep_email = contact.properties?.email || null;
            rep_name = `${contact.properties?.firstname || ''} ${contact.properties?.lastname || ''}`.trim() || null;
            lookup_method = rep_email ? 'association' : 'association_no_email';
          }
        } catch (err) {
          lookup_method = `error: ${err.message}`;
        }
      }

      stationDetails.push({
        station_code: code,
        found: !!station,
        rep_email,
        rep_name,
        lookup_method,
        station_id: station?.id || null
      });
    } catch (err) {
      stationDetails.push({
        station_code: code,
        found: false,
        error: err.message
      });
    }
  }

  // Use first station with a rep email as the current_recipient
  const primaryStation = stationDetails.find(s => s.rep_email) || stationDetails[0] || {};

  results.push({
    json: {
      ...data,
      current_recipient: {
        rep_email: primaryStation.rep_email || null,
        rep_name: primaryStation.rep_name || null
      },
      hubspot_context: {
        station_details: stationDetails,
        lookup_timestamp: new Date().toISOString()
      }
    }
  });
}

return results;

// Claude Triage - CLASSIFICATION ONLY (routing handled in code)
const ANTHROPIC_API_KEY = 'sk-ant-api03-YOUR_ANTHROPIC_KEY_HERE';

const systemPrompt = `You are an email triage assistant for USA North 811 (USAN) Member Services.

You analyze DPS (Department Alert System) alerts that came in with issue type "Other" and determine the REAL issue category.

BACKGROUND: USAN is a one-call center (811 service). Excavators call before they dig, tickets are generated, and member utilities must respond by locating/marking their underground lines. DPS agents categorize incoming alerts but sometimes select "Other" when the issue doesn't fit neatly or when they're unsure.

CLASSIFY into one of these categories:

- "no_response": Excavator reports the utility hasn't responded to a locate ticket. Urgent - excavator can't dig until lines are marked.
  EXAMPLES: "3rd attempt to get in touch with utility", "no response", "utility hasn't marked", "can't reach member"

- "contact_info_issue": Wrong phone/email on file for the member.
  EXAMPLES: "phone number is disconnected", "wrong number", "can't reach contact"

- "member_manually_added": Station code was manually added to a ticket.
  EXAMPLES: "manually added to ticket", "no members generated for area"

- "locator_complaint": Excavator complaining about locator behavior or work quality.
  EXAMPLES: "locator is unwilling to mark", "falsely stating no delineations", "wants supervisor"

- "aoi_mapping_issue": Member receiving wrong tickets or wants Area of Interest adjusted.
  EXAMPLES: "receiving non-related tickets", "decrease work radius", "wrong area"

- "ticket_delivery_issue": Member didn't receive a ticket or ticket not showing in system.
  EXAMPLES: "could not locate ticket", "didn't receive ticket"

- "system_status_issue": Portal/system issues like inactive status, DPP problems, positive response failures.
  EXAMPLES: "shows inactive", "issues providing positive response", "not populating in dropdown"

- "general": Relevant to the member but doesn't fit above categories.

OUTPUT FORMAT (respond with ONLY this JSON, no markdown):
{
  "classified_issue_type": "<category from above>",
  "confidence": "high|medium|low",
  "reasoning": "Brief explanation of classification",
  "inferred_company": null
}

IMPORTANT: If the station code is "N/A", missing, or invalid (like "001"), try to identify the company/utility from the notes and put it in "inferred_company". Do NOT include routing decisions - just classify.`;

const results = [];

for (const item of $input.all()) {
  const data = item.json;

  const stationCodesStr = (data.station_codes || []).join(', ');
  const statesStr = (data.states || []).join(', ');
  const repName = data.current_recipient?.rep_name || 'Unknown';
  const repEmail = data.current_recipient?.rep_email || 'Unknown';

  const userMessage = `Classify this DPS alert:

- Alert ID: ${data.alert_id}
- Ticket Number: ${data.ticket_number}
- Station Code(s): ${stationCodesStr}
- State: ${statesStr}
- Original Issue Type: Other
- Customer Name: ${data.customer_name || 'N/A'}
- Notes: ${data.notes || 'N/A'}

Member Rep on file: ${repName} (${repEmail})`;

  const requestBody = JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 512,
    system: systemPrompt,
    messages: [
      { role: 'user', content: userMessage }
    ]
  });

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: requestBody,
      timeout: 30000
    });

    results.push({
      json: {
        ...data,
        claude_raw_response: response.content[0].text,
        claude_model: response.model,
        claude_usage: response.usage,
        _prompt_sent: userMessage
      }
    });
  } catch (err) {
    results.push({
      json: {
        ...data,
        claude_error: err.message,
        claude_raw_response: null,
        _fallback: true,
        _prompt_sent: userMessage
      }
    });
  }
}

return results;

// Apply Triage Decision - DETERMINISTIC ROUTING RULES
const HS_TOKEN = 'Bearer pat-na1-YOUR_HUBSPOT_PAT_HERE';
const results = [];

// ===== ROUTING RULES (edit these, not the AI prompt) =====
const ROUTE_TO_REP = ['no_response', 'contact_info_issue', 'member_manually_added', 'general'];
const ROUTE_TO_MEMBERSERVICES = ['locator_complaint', 'aoi_mapping_issue', 'ticket_delivery_issue'];
// system_status_issue: route to rep (member needs DPP help from their rep)
// PGE* station codes: always manual_review
// N/A or missing station: always memberservices
// ==========================================================

for (const item of $input.all()) {
  const data = item.json;

  // Handle API failure — safe fallback
  if (data._fallback || !data.claude_raw_response) {
    results.push({
      json: {
        ...data,
        triage_decision: {
          classified_issue_type: 'unknown',
          confidence: 'none',
          reasoning: `Claude API failed: ${data.claude_error || 'No response'}`,
          fallback: true
        },
        routing_rule: 'fallback',
        final_routing: {
          send_to: 'memberservices@usan.org',
          send_to_name: 'Member Services',
          cc: [],
          template: 'general',
          is_fallback: true
        }
      }
    });
    continue;
  }

  // Parse Claude's classification
  let triage;
  try {
    let rawText = data.claude_raw_response.trim();
    if (rawText.startsWith('```')) {
      rawText = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
    }
    triage = JSON.parse(rawText);
  } catch (err) {
    results.push({
      json: {
        ...data,
        triage_decision: {
          classified_issue_type: 'parse_error',
          confidence: 'none',
          reasoning: `Failed to parse: ${err.message}`,
          raw_response: data.claude_raw_response,
          fallback: true
        },
        routing_rule: 'fallback',
        final_routing: {
          send_to: 'memberservices@usan.org',
          send_to_name: 'Member Services',
          cc: [],
          template: 'general',
          is_fallback: true
        }
      }
    });
    continue;
  }

  const classification = triage.classified_issue_type;
  const stationCodes = data.station_codes || [];
  const recipient = data.current_recipient || {};

  // ===== DETERMINISTIC ROUTING LOGIC =====

  let routeTo;
  let routingRule;

  // Rule 1: PGE station codes → always manual_review
  const hasPGE = stationCodes.some(c => (c || '').toUpperCase().startsWith('PGE'));
  if (hasPGE) {
    routeTo = 'manual_review';
    routingRule = 'pge_manual_review';
  }
  // Rule 2: N/A or missing station → memberservices (can't identify rep)
  else if (stationCodes.length === 0 || stationCodes.every(c => !c || c === 'N/A' || c === '001')) {
    routeTo = 'memberservices';
    routingRule = 'no_valid_station';
  }
  // Rule 3: Classification-based routing
  else if (ROUTE_TO_REP.includes(classification)) {
    routeTo = 'rep';
    routingRule = 'classification_to_rep';
  }
  else if (ROUTE_TO_MEMBERSERVICES.includes(classification)) {
    routeTo = 'memberservices';
    routingRule = 'classification_to_memberservices';
  }
  // Rule 4: system_status_issue → rep (member needs DPP help)
  else if (classification === 'system_status_issue') {
    routeTo = 'rep';
    routingRule = 'system_status_to_rep';
  }
  // Rule 5: Unknown classification → memberservices
  else {
    routeTo = 'memberservices';
    routingRule = 'unknown_classification_fallback';
  }

  // ===== BUILD FINAL ROUTING =====

  let finalRouting;
  let inferredLookup = null;

  // If routing to rep but we need to infer the company
  if (routeTo === 'rep' && triage.inferred_company && !recipient.rep_email) {
    try {
      const searchResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.hubapi.com/crm/v3/objects/2-35681060/search',
        headers: { 'Authorization': HS_TOKEN, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          filterGroups: [{
            filters: [{
              propertyName: 'station_code',
              operator: 'CONTAINS_TOKEN',
              value: triage.inferred_company.replace(/[^a-zA-Z0-9]/g, '').substring(0, 10)
            }]
          }],
          properties: ['station_code', 'station_email', 'station_contact_name'],
          limit: 5
        })
      });
      if (searchResponse.results && searchResponse.results.length > 0) {
        const station = searchResponse.results[0];
        inferredLookup = {
          found: true,
          station_code: station.properties?.station_code,
          rep_email: station.properties?.station_email,
          rep_name: station.properties?.station_contact_name
        };
      } else {
        inferredLookup = { found: false, searched_for: triage.inferred_company };
        routeTo = 'memberservices';
        routingRule += '_inferred_not_found';
      }
    } catch (err) {
      inferredLookup = { found: false, error: err.message };
      routeTo = 'memberservices';
      routingRule += '_lookup_error';
    }
  }

  switch (routeTo) {
    case 'rep': {
      const repEmail = inferredLookup?.rep_email || recipient.rep_email;
      const repName = inferredLookup?.rep_name || recipient.rep_name;
      finalRouting = {
        send_to: repEmail || 'memberservices@usan.org',
        send_to_name: repName || 'Member Services',
        cc: triage.confidence === 'low' ? ['memberservices@usan.org'] : [],
        template: classification,
        is_fallback: !repEmail
      };
      break;
    }
    case 'manual_review':
      finalRouting = {
        send_to: 'memberservices@usan.org',
        send_to_name: 'Member Services',
        cc: [],
        template: 'manual_review',
        requires_human_review: true,
        is_fallback: false
      };
      break;
    default:
      finalRouting = {
        send_to: 'memberservices@usan.org',
        send_to_name: 'Member Services',
        cc: [],
        template: classification,
        is_fallback: false
      };
  }

  results.push({
    json: {
      ...data,
      triage_decision: triage,
      routing_rule: routingRule,
      inferred_lookup: inferredLookup,
      final_routing: finalRouting
    }
  });
}

return results;

